        farm: { owned: 0, baseCost: 1100, cps: 8, name: 'Farm', desc: 'Grows cookie plants from cookie seeds' },
        mine: { owned: 0, baseCost: 12000, cps: 47, name: 'Mine', desc: 'Mines out cookie dough and chips' },
