      const amount = gameState.cookiesPerClick;
      gameState.cookies += amount;

      const rect = cookieEl.getBoundingClientRect();
      const x = e.clientX || (rect.left + rect.width / 2);
      const y = e.clientY || (rect.top + rect.height / 2);
