      for (const key in gameState.upgrades) {
        const cost = getUpgradeCost(gameState.upgrades[key]);
        const affordable = gameState.cookies >= cost;
        if (lastAffordability[key] !== affordable) {
          lastAffordability[key] = affordable;
          changed = true;
        }
      }
      return changed;
    }

    function gameLoop() {
      if (gameState.cookiesPerSecond > 0) {
        const gain = gameState.cookiesPerSecond / 10;
        gameState.cookies += gain;
        updateDisplay();
        if (checkAffordabilityChanged()) {
          renderUpgrades();
        }
      }
    }

