        }
      }
    }

    function saveGame() {
      localStorage.setItem('cookieClickerSave', JSON.stringify(gameState));
    }

    function loadGame() {
      const save = localStorage.getItem('cookieClickerSave');
      if (save) {
        const loaded = JSON.parse(save);
        gameState.cookies = loaded.cookies || 0;
        gameState.cookiesPerClick = loaded.cookiesPerClick || 1;

        if (loaded.upgrades) {
          for (const key in gameState.upgrades) {
            if (loaded.upgrades[key]) {
              gameState.upgrades[key].owned = loaded.upgrades[key].owned || 0;
            }
          }
        }

        calculateCPS();
        updateDisplay();
        renderUpgrades();
      }
    }

    cookieEl.addEventListener('click', clickCookie);

    loadGame();
    renderUpgrades();
    updateDisplay();

    setInterval(gameLoop, 100);
    setInterval(saveGame, 10000);
  </script>
